// Normalized vocabulary decks for the study tools (Flashcards, Memory Match):
// flatten a set's answers into plain { id, zh, py, en, fr } cards.
function toCards(set) {
  return set.map((i) => ({ id: i.id, zh: i.answer.zh, py: i.answer.py, en: i.answer.en, fr: i.answer.fr }));
}

